import{_ as t,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const i=JSON.parse('{"title":"长期主义","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/长期主义.md","filePath":"05_quotes/by-theme/长期主义.md"}'),c={name:"05_quotes/by-theme/长期主义.md"};function q(l,o,r,p,h,n){return e(),a("div",null,[...o[0]||(o[0]=[u('<h1 id="长期主义" tabindex="-1">长期主义 <a class="header-anchor" href="#长期主义" aria-label="Permalink to &quot;长期主义&quot;">​</a></h1><blockquote><p>&quot;如果你不打算持有一只股票十年，那连持有十分钟都不要考虑。&quot;——巴菲特</p></blockquote><p>长期主义是巴菲特投资哲学的底层逻辑，也是区分真正的投资者和投机者的分水岭。</p><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;投资的第一条规则是不要亏损。第二条规则是不要忘记第一条。&quot;</p></blockquote><blockquote><p>&quot;如果你不打算持有一只股票十年，那连持有十分钟都不要考虑。我们从不试图从短期的股价波动中获利。&quot;</p></blockquote><blockquote><p>&quot;我们喜欢持有的时间是：永远。如果一家企业有好生意、好管理，而且价格合理，就不要卖掉它。&quot;</p></blockquote><blockquote><p>&quot;在伯克希尔，我所做的就是找到好的企业，信任好的管理层，然后坐在那里什么都不做。复利在发挥作用。&quot;</p></blockquote><blockquote><p>&quot;我们从不试图对宏观经济做出预测，也不对市场的短期走势做出预测。我们只关注企业的长期价值。&quot;</p></blockquote><blockquote><p>&quot;真正优秀的企业，应该让你的孙子辈依然持有。如果你在考虑明天要不要卖出，那当初就不应该买。&quot;</p></blockquote><blockquote><p>&quot;市场是为投资者服务的，不是为指导的。我们从市场短期波动中一无所获，也从不试图从中获利。&quot;</p></blockquote><blockquote><p>&quot;时间是优秀企业的朋友，是平庸企业的敌人。&quot;</p></blockquote><hr><h2 id="伯克希尔的实践" tabindex="-1">伯克希尔的实践 <a class="header-anchor" href="#伯克希尔的实践" aria-label="Permalink to &quot;伯克希尔的实践&quot;">​</a></h2><p>1965年巴菲特接手伯克希尔时，纺织业务的资本回报率极低。但他没有急于退出，而是用纺织业务产生的现金，一步步收购保险业务，再用保险浮存金投资，最终建立了商业帝国。</p><blockquote><p>&quot;在伯克希尔的早期，我们的纺织业务只能勉强维持生存。但它产生的每一分钱现金，都被用来购买更好的资产。这个过程持续了很多年。&quot;</p></blockquote><blockquote><p>&quot;好的企业加上时间，等于卓越的结果。&quot;</p></blockquote><blockquote><p>&quot;查理和我从未试图在市场的短期波动中寻找盈利机会。相反，我们利用市场的短期情绪来为我们服务——在别人恐慌时买入，在别人贪婪时保持冷静。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1965年 · 1977年 · 1987年 · 1996年 · 2005年 · 2014年 · 2020年</p><hr><h2 id="深入阅读" tabindex="-1">深入阅读 <a class="header-anchor" href="#深入阅读" aria-label="Permalink to &quot;深入阅读&quot;">​</a></h2><p><a href="/02_concepts/intrinsic-value.html">内在价值</a> · <a href="/02_concepts/compounding.html">复利</a> · <a href="/02_concepts/safety-margin.html">安全边际</a> · <a href="/02_concepts/circle-of-competence.html">能力圈</a></p>',25)])])}const s=t(c,[["render",q]]);export{i as __pageData,s as default};
